import React, { useState } from "react";

function IndividualAnalysis({ customerData, onInputChange, onAnalyze, loading, results }) {
  const [activeTab, setActiveTab] = useState("core");

  const handleChange = (e) => {
    const { name, value } = e.target;
    onInputChange({ ...customerData, [name]: value });
  };

  const renderField = (label, name, type = "number", options = null) => (
    <div className="field">
      <label>{label}</label>
      {options ? (
        <select name={name} value={customerData[name]} onChange={handleChange}>
          {options.map((opt, i) => (
            <option key={i} value={opt}>
              {opt}
            </option>
          ))}
        </select>
      ) : (
        <input type={type} name={name} value={customerData[name]} onChange={handleChange} />
      )}
    </div>
  );

  return (
    <div className="tabbed-layout">
      {/* Tabs */}
      <div className="tabs glass-blur">
        <button
          className={`tab-btn ${activeTab === "core" ? "active" : ""}`}
          onClick={() => setActiveTab("core")}
        >
          💰 Core Metrics
        </button>
        <button
          className={`tab-btn ${activeTab === "logistics" ? "active" : ""}`}
          onClick={() => setActiveTab("logistics")}
        >
          🛠️ Service & Logistics
        </button>
        <button
          className={`tab-btn ${activeTab === "demographics" ? "active" : ""}`}
          onClick={() => setActiveTab("demographics")}
        >
          🧑‍ Demographics
        </button>
      </div>

      {/* Tab Summary */}
      <div className="tab-summary">
        {activeTab === "core" && <p>💰 7 Key Customer Performance Indicators</p>}
        {activeTab === "logistics" && <p>🛠️ 7 Service and Experience Metrics</p>}
        {activeTab === "demographics" && <p>🧑‍ 4 Demographic Attributes</p>}
      </div>

      {/* Loading Progress */}
      {loading && (
        <div className="progress-bar">
          <div className="progress-fill"></div>
        </div>
      )}

      {/* Tab Panels */}
      <div className="tab-content fade-in">
        {activeTab === "core" && (
          <div className="section-card">
            <h2>💰 Core Metrics</h2>
            <div className="grid">
              {renderField("Tenure", "Tenure")}
              {renderField("Order Count", "OrderCount")}
              {renderField("Cashback Amount", "CashbackAmount")}
              {renderField("Order Hike %", "OrderAmountHikeFromlastYear")}
              {renderField("Coupon Used", "CouponUsed")}
              {renderField("Devices Registered", "NumberOfDeviceRegistered")}
              {renderField("Satisfaction Score", "SatisfactionScore")}
            </div>
          </div>
        )}

        {activeTab === "logistics" && (
          <div className="section-card">
            <h2>🛠️ Service & Logistics</h2>
            <div className="grid">
              {renderField("Days Since Last Order", "DaySinceLastOrder")}
              {renderField("Hours On App", "HourSpendOnApp")}
              {renderField("Warehouse Distance", "WarehouseToHome")}
              {renderField("Addresses", "NumberOfAddress")}
              {renderField("Complaint", "Complain", "select", ["0", "1"])}
              {renderField("Login Device", "PreferredLoginDevice", "select", [
                "Mobile Phone",
                "Computer",
                "Tablet",
              ])}
              {renderField("Order Category", "PreferedOrderCat", "select", [
                "Laptop & Accessory",
                "Mobile & Accessory",
                "Grocery",
                "Fashion",
              ])}
            </div>
          </div>
        )}

        {activeTab === "demographics" && (
          <div className="section-card">
            <h2>🧑‍ Demographics</h2>
            <div className="grid">
              {renderField("Gender", "Gender", "select", ["Male", "Female", "Other"])}
              {renderField("Marital Status", "MaritalStatus", "select", ["Married", "Single"])}
              {renderField("City Tier", "CityTier")}
              {renderField("Payment Mode", "PreferredPaymentMode", "select", [
                "Credit Card",
                "Debit Card",
                "UPI",
                "Net Banking",
              ])}
            </div>
          </div>
        )}
      </div>

      {/* Action Button */}
      <button className="analyze-btn" onClick={onAnalyze} disabled={loading}>
        {loading ? "Analyzing..." : "🚀 Run Prediction"}
      </button>

      {/* Results */}
      {results && (
        <div className="results-card">
          <h3>📊 Prediction Results</h3>
          <pre>{JSON.stringify(results, null, 2)}</pre>
        </div>
      )}
    </div>
  );
}

export default IndividualAnalysis;
